\begin{theorem}
Let $m_1$, $m_2$, $\widehat{m}_1$, $\widehat{m}_2$ denote Runge--Kutta methods, such that
\[
\widehat{m}_1 \equiv m_1 \quad \text{and} \quad \widehat{m}_2 \equiv m_2. \tag{382f}
\]
Then
\[
[m_1 \cdot m_2] = [\widehat{m}_1 \cdot \widehat{m}_2].
\]
\end{theorem}

\begin{lemma}
Let $\alpha$ and $\beta$ be multiplicative mappings from the forests to the real numbers. Then $\alpha\beta$ is multiplicative.
\end{lemma}

\begin{proof}
It will be sufficient to consider the value of $(\alpha\beta)(S)$, where $S = S_1 \cup S_2$.
Each $R \subseteq S$ can be written as $R = R_1 \cup R_2$, where $R_1 \subseteq S_1$ and $R_2 \subseteq S_2$. We now have
\[
\begin{aligned}
(\alpha\beta)(S) &= \sum_{R \subseteq S} \alpha(S \setminus R)\beta(R) \\
&= \sum_{R_1 \subseteq S_1} \alpha(S_1 \setminus R_1)\beta(R_1) \sum_{R_2 \subseteq S_2} \alpha(S_2 \setminus R_2)\beta(R_2) \\
&= (\alpha\beta)(S_1)(\alpha\beta)(S_2).
\end{aligned}
\]
We next show that the product we have defined is associative.
\end{proof}

\begin{lemma}
Let $\alpha$, $\beta$ and $\gamma$ be multiplicative mappings from forests to reals. Then
\[
(\alpha\beta)\gamma = \alpha(\beta\gamma).
\]
\end{lemma}

\begin{proof}
If $Q \subseteq R \subseteq S$ then $(R \setminus Q) \subseteq (S \setminus Q)$. Hence, we find
\begin{align*}
((\alpha\beta)\gamma)(S) &= \sum_{Q \subseteq S} (\alpha\beta)(S \setminus Q)\gamma(Q) \\
&= \sum_{Q \subseteq S} \sum_{(R \setminus Q) \subseteq (S \setminus Q)} \alpha((S \setminus Q) \setminus (R \setminus Q))\beta(R \setminus Q)\gamma(Q) \\
&= \sum_{Q \subseteq R \subseteq S} \alpha(S \setminus R)\beta(R \setminus Q)\gamma(Q) \\
&= \sum_{R \subseteq S} \alpha(S \setminus R)(\beta\gamma)(R) \\
&= (\alpha(\beta\gamma))(S).
\end{align*}

We can now restrict multiplication to trees, and we note that associativity still remains. The semi-group that has been constructed on the set $G_{1}$ is actually a group because we can construct both left and right inverses, $\alpha_{\text{left}}^{-1}$ and $\alpha_{\text{right}}^{-1}$ say, for any $\alpha \in G_{1}$, which must be equal because
\[
\alpha_{\text{left}}^{-1} = \alpha_{\text{left}}^{-1} (\alpha \alpha_{\text{right}}^{-1}) = (\alpha_{\text{left}}^{-1} \alpha) \alpha_{\text{right}}^{-1} = \alpha_{\text{right}}^{-1}.
\]
\end{proof}

\begin{theorem}
For $\alpha \in G_1$ and $\beta \in G$,
\[
\begin{array}{rcl}
(\alpha\beta)(\emptyset) & = & \beta(\emptyset), \\
(\alpha\beta)(t) & = & \lambda(\alpha, t)(\beta) + \alpha(t)\beta(\emptyset).
\end{array}
\]
\end{theorem}

\begin{theorem}
If $\alpha \in G_1$ such that $\alpha(\tau) = 1$, and $m$ is an integer with $m \notin \{0, 1, -1\}$, then $\alpha^{(m)} = \alpha^m$ implies that $\alpha = E$.
\end{theorem}

\begin{proof}
For any tree $t \neq \tau$, we have $\alpha^{(m)}(t) = r(t)^m \alpha(t) + Q_1$ and $\alpha^m(t) = m\alpha(t) + Q_2$, where $Q_1$ and $Q_2$ are expressions involving $\alpha(u)$ for $r(u) < r(t)$. Suppose that $\alpha(u)$ has been proved equal to $E(u)$ for all such trees. Then
\begin{align*}
\alpha^{(m)}(t) &= r(t)^m \alpha(t) + Q_1, \\
\alpha^m(t) &= m\alpha(t) + Q_2, \\
E^{(m)}(t) &= r(t)^m E(t) + Q_1, \\
E^m(t) &= mE(t) + Q_2,
\end{align*}
so that $\alpha^{(m)}(t) = \alpha^m(t)$ implies that
\[
(r(t)^m - m)(\alpha(t) - E(t)) = 0,
\]
implying that $\alpha(t) = E(t)$, because $r(t)^m \neq m$ whenever $r(t) > 1$ and $m \notin \{0, 1, -1\}$.

Of the three excluded values of $m$ in Theorem~\ref{thm:387A}, only $m = -1$ is interesting. Methods for which $\alpha^{(-1)} = \alpha^{-1}$ have a special property which makes them of potential value as the source of efficient extrapolation procedures. Consider the solution of an initial value problem over an interval $[x_0, x]$ using $n$ steps of a Runge--Kutta method with stepsize $h = (x - x_0)/n$. Suppose the computed solution can be expanded in an asymptotic series in $h$,
\[
y(x) + \sum_{i=1}^\infty C_i h^i. \tag{387e}
\]
If the elementary weight function for the method is $\alpha$, then the method corresponding to $(\alpha^{(-1)})^{-1}$ exactly undoes the work of the method but with $h$ reversed. This means that the asymptotic error expansion for this reversed method would correspond to changing the sign of $h$ in \eqref{eq:387e}. If $\alpha = (\alpha^{(-1)})^{-1}$, this would give exactly the same expansion, so that \eqref{eq:387e} is an even function. It then becomes possible to extend the applicability of the method by extrapolation in even powers only.
\end{proof}

\begin{theorem}
Let \(\alpha \in G_1\), \(\beta \in G_1\), \(\gamma \in G\) and \(\delta \in G\) be such that
\[
\alpha = \beta + H_p \quad \text{and} \quad \gamma = \delta + H_p.
\]
Then \(\alpha\gamma = \beta\delta + H_p\).
\end{theorem}

\begin{proof}
Two members of \(G\) differ by a member of \(H_p\) if and only if they take
identical values for any \(t\) such that \(r(t) \leq p\). For any such \(t\), the formula
for \((\alpha\gamma)(t)\) involves only values of \(\alpha(u)\) and \(\gamma(u)\) for \(r(u) < r(t)\). Hence,
\((\alpha\gamma)(t) = (\beta\delta)(t)\).

An alternative interpretation of \(H_p\) is to use instead \(1 + H_p \in G_1\) as a
subgroup of \(G_1\). We have:
\end{proof}

\begin{theorem}
Let \(\alpha, \beta \in G_{1}\); then
\[
\alpha = \beta + H_{p} \tag{388a}
\]
if and only if
\[
\alpha = \beta(1 + H_{p}). \tag{388b}
\]
\end{theorem}

\begin{proof}
Both \eqref{eq:388a} and \eqref{eq:388b} are equivalent to the statement \(\alpha(t) = \beta(t)\) for all \(t\) such that \(r(t) \leq p\).

Furthermore, we have:
\end{proof}

\begin{definition}
A member $\alpha$ of $G_1$ is in $C(\xi)$ if, for any tree $t$ such that $r(t) \leq \xi$, $\alpha(t) = \gamma(t)^{-1} \alpha(\tau)^{r(t)}$ and also
\[
\alpha([t\, t_1 t_2 \cdots t_m]) = \frac{1}{\gamma(t)} \alpha([\tau^{r(t)} t_1 t_2 \cdots t_m]), \tag{388c}
\]
for any $t_1 t_2 \cdots t_m \in T$.
\end{definition}

\begin{theorem}
The set $C(\xi)$ is a normal subgroup of $G_1$.

A proof of this result, and of Theorem~\ref{thm:388G} below, is given in Butcher (1972).
The $D(\xi)$ condition is also represented by a subset of $G_1$, which is also known to generate a normal subgroup.
\end{theorem}

\begin{theorem}
The set $D(\xi)$ is a normal subgroup of $G_1$.

The importance of these semi-groups is that $E$ is a member of each of them and methods can be constructed which also lie in them. We first prove the following result:
\end{theorem}

\begin{lemma}
A Runge--Kutta method with corresponding group element $\alpha$
has effective order $p$ if and only if (389a) holds, where $\beta$ is such that $\beta(\tau) = 0$.
\end{lemma}

\begin{definition}
Consider a linear multistep method used with a starting method as described in the previous discussion. Let $Y_m$ denote the approximation to $y(x)$ found using $m$ steps with $h = (x - x_0)/m$. The function $f$ is assumed to be continuous and to satisfy a Lipschitz condition in its second variable. The linear multistep method is said to be `convergent' if, for any such initial value problem,
\[
Y_m - y(x) \to 0, \quad \text{as } m \to \infty.
\]
\end{definition}

\begin{definition}
A linear multistep method $[\alpha, \beta]$ is `stable' if the difference equation \eqref{eq:403a} has only bounded solutions.

Because stability concepts of one sort or another abound in the theory of initial value problems, `stability' is often referred to as `zero-stability' -- for example, in Lambert (1991) -- or as `stability in the sense of Dahlquist'.
\end{definition}

\begin{theorem}
Let $\mathbf{n}$ denote the vector
\[
\mathbf{n} = y(x_n) - y_n.
\]
Then for $h_0$ sufficiently small so that $h_0 |\beta_0| L < 1$ and $h < h_0$, there exist constants $C$ and $D$ such that
\[
\left\| \mathbf{n} - \sum_{i=1}^k \alpha_i \mathbf{n}_{-i} \right\| \leq C h \max_{i=1}^k \| \mathbf{n}_{-i} \| + D h^2. \tag{406c}
\]
\end{theorem}

\begin{proof}
The value of $\mathbf{n} - \sum_{i=1}^k \alpha_i \mathbf{n}_{-i} - h \sum_{i=0}^k \beta_i \big( f(y(x_{n-i})) - f(y_{n-i}) \big)$ is the difference of two terms, of which the first can be bounded by a constant times $h^2$, by Theorem~\ref{thm:406B}, and the second is zero. This means that
\[
\mathbf{n} - \sum_{i=1}^k \alpha_i \mathbf{n}_{-i} = T_1 + T_2 + T_3, \tag{406d}
\]
where
\begin{align*}
T_1 &= h|\beta_0| \big( f(y(x_n)) - f(y_n) \big) \leq h L |\beta_0| \cdot \| \mathbf{n} \|, \tag{406e} \\
T_2 &= h \left\| \sum_{i=1}^k \beta_i \big( f(y(x_{n-i})) - f(y_{n-i}) \big) \right\| \leq h L \sum_{i=1}^k |\beta_i| \max_{i=1}^k \| \mathbf{n}_{-i} \|, \tag{406f}
\end{align*}
and $T_3$ can be bounded in terms of a constant times $h^2$. We now use \eqref{eq:406d} twice. First, assuming $h \leq h_0$, obtain a bound on $(1 - h L |\beta_0|) \| \mathbf{n} \|$ in terms of $\max_{i=1}^k \| \mathbf{n}_{-i} \|$ and terms that are bounded by a constant times $h^2$. Hence, obtain a bound on $\| \mathbf{n} \|$. Then, by inserting this preliminary result in the bound on $T_1$, we obtain the result of the theorem.
\end{proof}

\begin{theorem}
A linear multistep formula $[\alpha, \beta]$ has order $p$ if and only if
\[
\frac{z}{\log(1 + z)} \alpha(1 + z) + \beta(1 + z) = O(z^{p}).
\]
\end{theorem}

\begin{definition}
Corresponding to a linear multistep method $[\alpha, \beta]$, the member of $\mathcal{G}_1$ represents the `underlying one-step method'.  
As we have already remarked, the mapping $\Phi$ in \eqref{eq:422b}, if it exists in more than a notional sense, is really the object of interest and this really is the underlying one-step method.
\end{definition}

\begin{theorem}
An A-stable linear multistep method cannot have order greater than 2.
\end{theorem}

\begin{proof}
If the order were greater than 2, there would be more than three up arrows emanating from the origin. At least three of these up arrows would come out in the positive direction (or possibly would be tangential to the imaginary axis). Since there is only one pole, at least two of these arrows would cross the imaginary axis (or be tangential to it). Hence, the stability region does not include all of the imaginary axis and the method is not A-stable.

We can make this result more precise by obtaining a bound on the error constant for second order A-stable methods. The result yields an optimal role for the second order Adams--Moulton method, for which the error constant is $-\frac{1}{12}$, because
\[
\exp(z) - \frac{1 + \frac{1}{2}z}{1 - \frac{1}{2}z} = -\frac{1}{12}z^{3} + O(z^{4}).
\]
It is not possible to obtain a positive error constant amongst A-stable second order methods, and it is not possible to obtain an error constant smaller in magnitude than for the one-step Adams--Moulton method. To prove the result we use, in place of $\exp(z)$, the special stability function $(1 + \frac{1}{2}z)/(1 - \frac{1}{2}z)$ in forming a relative stability function.
\end{proof}

\begin{definition}
A one-leg method $[\alpha, \beta]$ is `G-stable' if $M$ given by \eqref{eq:451e} is positive semi-definite.

We present the example of the BDF2 method with
\[
[\alpha(z), \beta(z)] = \left( 1 - \frac{4}{3}z + \frac{1}{3}z^{2}, \frac{2}{3} \right).
\]
Write
\[
G = \begin{pmatrix}
g_{11} & g_{12} \\
g_{12} & g_{22}
\end{pmatrix}
\]
and we find
\[
M = \begin{bmatrix}
\frac{3}{4} - g_{11} & -\frac{8}{9} - g_{12} & \frac{2}{9} \\[2pt]
-\frac{8}{9} - g_{12} & g_{11} - g_{22} & g_{12} \\[2pt]
\frac{2}{9} & g_{12} & g_{22}
\end{bmatrix},
\]
which is positive semi-definite if and only if $G$ is the positive definite matrix
\[
G = \begin{pmatrix}
\frac{10}{9} & -\frac{4}{9} \\[2pt]
-\frac{4}{9} & \frac{2}{9}
\end{pmatrix}.
\]

Denote the point at which the derivative is calculated in step $n$ of a one-leg method by $\widehat{y}_{n}$. Also denote the corresponding $x$ argument as $\widehat{x}_{n}$. Hence, we have
\begin{align}
\widehat{x}_{n} &= x_{n} - \frac{\sum_{i=0}^{k} i\beta_{i}}{\sum_{i=0}^{k} \beta_{i}} h, \label{eq:452a} \\
\widehat{y}_{n} &= \left( \sum_{i=0}^{k} \beta_{i} \right)^{-1} \sum_{i=0}^{k} \beta_{i} y_{n-i}, \label{eq:452b} \\
y_{n} &= \sum_{i=1}^{k} \alpha_{n-i} y_{n-i} + \left( \sum_{i=0}^{k} \beta_{i} \right) f(\widehat{x}_{n}, \widehat{y}_{n}). \label{eq:452c}
\end{align}

Form a linear combination of $\widehat{y}_{n-i}$, $i = 0, 1, \dots, k$, given by \eqref{eq:452b}, based on the coefficients in the $\alpha$ polynomial, and note that the operators $\alpha(E^{-1})$ and $\beta(E^{-1})$ are commutative. We have
\[
\widehat{y}_{n} - \sum_{i=1}^{k} \alpha_{i} \widehat{y}_{n-i} = h \sum_{i=1}^{k} \beta_{i} f(\widehat{x}_{n}, \widehat{y}_{n}). \label{eq:452d}
\]

The relationship between the $y$ and $\widehat{y}$ sequences given by \eqref{eq:452b} and \eqref{eq:452d} was suggested by Dahlquist (1976) as an indication that stability questions for a linear multistep method can be replaced by similar questions for the corresponding one-leg method.
\end{definition}

\begin{definition}
A general linear method $(A, U, B, V)$ is `preconsistent' if there exists a vector $u$ such that
\[
V u = u, \tag{510a}
\]
\[
U u = 1. \tag{510b}
\]
The vector $u$ is the `preconsistency vector'.
\end{definition}

\begin{definition}
A general linear method $(A, U, B, V)$ is `consistent' if it is preconsistent with preconsistency vector $u$ and there exists a vector $v$ such that
\[
B\mathbf{1} + V v = u + v. \tag{510c}
\]

Just as for linear multistep methods, we need a concept of stability. In the general linear case this is defined in terms of the power-boundedness of $V$ and, as we shall see, is related to the solvability of the problem $y' = 0$.
\end{definition}

\begin{definition}
A general linear method $(A, U, B, V)$ is `stable' if there exists a constant $C$ such that, for all $n = 1, 2, \dots$, $\|V^n\| \leq C$.
\end{definition}

\begin{theorem}
A stable and consistent general linear method is convergent.
\end{theorem}

\begin{definition}
A general linear method is `A-stable' if $M(z)$ is power-bounded for every $z$ in the left half complex plane.

Just as for Runge--Kutta and linear multistep methods, A-stability is the ideal property for a method to possess for it to be applicable to stiff problems.

Corresponding to the further requirement for Runge--Kutta methods that $R(\infty) = 0$, we have the generalization of L-stability to general linear methods.
\end{definition}

\begin{definition}
A general linear method is \textit{L-stable} if it is A-stable and
\[
\rho(M(\infty)) = 0.
\]
\end{definition}

\begin{theorem}
For given $\nu$, the maximum possible stability order is given by
\[
p^* = \sum_{j=0}^{k} (\nu_j + 1) - 2. \tag{521a}
\]
\end{theorem}

\begin{definition}
A starting method $S$ defined by the generalized Runge--Kutta methods \eqref{eq:530a}, for $i = 1, 2, \dots, r$, is `degenerate' if $b_0^{(i)} = 0$, for $i = 1, 2, \dots, r$, and `non-degenerate' otherwise.
\end{definition}

\begin{definition}
Consider a general linear method $\mathcal{M}$ and a non-degenerate starting method $\mathcal{S}$. The method $\mathcal{M}$ has order $p$ relative to $\mathcal{S}$ if the results found from $\mathcal{S}\mathcal{M}$ and $\mathcal{E}\mathcal{S}$ agree to within $O(h^{p+1})$.
\end{definition}

\begin{definition}
A general linear method $\mathbf{M}$ has order $p$ if there exists a non-degenerate starting method $\mathbf{S}$ such that $\mathbf{M}$ has order $p$ relative to $\mathbf{S}$.
\end{definition}

\begin{theorem}
Let $M = (A, U, B, V)$ denote a general linear method and let $\xi$ denote the algebraic representation of a starting method $S$. Assume that \eqref{eq:532e} and \eqref{eq:532f} hold in $G/H^p$. Denote
\[
\Gamma = E\xi - B\eta D - V\xi, \quad \text{in } G.
\]
Then the Taylor expansion of $S(y(x_0 + h)) - M(S(y(x_0)))$ is
\[
\sum_{r(t) \ge p} \frac{h^{r(t)}}{\sigma(t)} F(t)(y(x_0)). \tag{532g}
\]
\end{theorem}

\begin{proof}
We consider a single step from initial data given at $x_0$ and consider the Taylor expansion of various expressions about $x_0$. The input approximation, computed by $S$, has Taylor series represented by $\xi$. Suppose the Taylor expansions for the stage values are represented by $\eta$ so that the stage derivatives will be represented by $\eta D$ and these will be related by \eqref{eq:532e}. The Taylor expansion for the output approximations is represented by $B\eta D + V\xi$, and this will agree with the Taylor expansion of $S(y(x_0 + h))$ up to $h^p$ terms if \eqref{eq:532f} holds. The difference from the target value of $S(y(x_0 + h))$ is given by \eqref{eq:532g}.
\end{proof}

\begin{theorem}
The following method has order 4 and stage order 2:
\[
\begin{array}{c}
A \quad U \\
B \quad V
\end{array}
=
\left[\begin{array}{cccc}
\displaystyle \frac{3+\sqrt{3}}{6} & 0 & \displaystyle \frac{1}{3} & \displaystyle -\frac{3+2\sqrt{3}}{3} \\[6pt]
\displaystyle -\frac{\sqrt{3}}{3} & \displaystyle -\frac{3+\sqrt{3}}{6} & \displaystyle \frac{1}{3} & \displaystyle \frac{3+2\sqrt{3}}{3} \\[6pt]
\displaystyle \frac{1}{2} & \displaystyle \frac{1}{2} & 1 & 0 \\[6pt]
\displaystyle \frac{1}{2} & \displaystyle -\frac{1}{2} & 0 & -1
\end{array}\right]. \tag{534a}
\]
Before verifying this result we need to specify the nature of the starting method $S$ and the values of the stage abscissae, $c_1$ and $c_2$. From an initial point $(x_0, y_0)$, the starting value is given by
\[
\begin{aligned}
y_1^{[0]} &= y_0, \\
y_2 &= \frac{1}{2\sqrt{3}} h^2 y''(x_0) - \frac{\sqrt{3}}{108} h^4 y^{(4)}(x_0) + \frac{9+5\sqrt{3}}{18}.
\end{aligned}
\]
\end{theorem}

\begin{corollary}
If
\[
\chi(\lambda) = \begin{bmatrix}
1 & \lambda + \alpha_1 & \lambda^2 + \alpha_1 \lambda + \alpha_2 & \cdots & \lambda^{n-1} + \alpha_1 \lambda^{n-2} + \cdots + \alpha_{n-1}
\end{bmatrix},
\]
then
\[
\Psi^{-1} = \begin{bmatrix}
\chi(\lambda) & \frac{1}{1!} \chi'(\lambda) & \cdots & \frac{1}{(n-2)!} \chi^{(n-2)}(\lambda) & \frac{1}{(n-1)!} \chi^{(n-1)}(\lambda)
\end{bmatrix}.
\]
\end{corollary}

